	invalidate(): void;
	localToGlobal(pos: Engine3D_core_geom_Point): Engine3D_core_geom_Point;
	get_color(): number;
	set_color(value: number): number;
	get_contentsScaleFactor(): number;
	get_displayState(): openfl_display_StageDisplayState;
	set_displayState(value: openfl_display_StageDisplayState): openfl_display_StageDisplayState;
	get_focus(): openfl_display_InteractiveObject;
	set_focus(value: openfl_display_InteractiveObject): openfl_display_InteractiveObject;
	get_frameRate(): number;
	set_frameRate(value: number): number;
	get_fullScreenHeight(): number;
	get_fullScreenSourceRect(): Engine3D_core_geom_Rectangle;
	set_fullScreenSourceRect(value: Engine3D_core_geom_Rectangle): Engine3D_core_geom_Rectangle;
	get_fullScreenWidth(): number;
	get_quality(): openfl_display_StageQuality;
	set_quality(value: openfl_display_StageQuality): openfl_display_StageQuality;
	get_scaleMode(): openfl_display_StageScaleMode;
	set_scaleMode(value: openfl_display_StageScaleMode): openfl_display_StageScaleMode;
