/**
 * Stage3DProxy provides a proxy class to manage a single Stage3D instance as well as handling the creation and
 * attachment of the Context3D (and in turn the back buffer) is uses. Stage3DProxy should never be created directly,
 * but requested through Stage3DManager.
 *
 * @see away3d.core.managers.Stage3DProxy
 *
 * todo: consider moving all creation methods (createVertexBuffer etc) in here, so that disposal can occur here
 * along with the context, instead of scattered throughout the framework
 */
export class away3d_core_managers_Stage3DProxy extends Engine3D_core_events_EventDispatcher {
	/**
	 * Creates a Stage3DProxy object. This method should not be called directly. Creation of Stage3DProxy objects should
	 * be handled by Stage3DManager.
	 * @param stage3DIndex The index of the Stage3D to be proxied.
	 * @param stage3D The Stage3D to be proxied.
	 * @param stage3DManager
	 * @param forceSoftware Whether to force software mode even if hardware acceleration is available.
	 */
	constructor(stage3DIndex: number, stage3D: openfl_display_Stage3D, stage3DManager: away3d_core_managers_Stage3DManager, forceSoftware?: boolean, profile?: string);
	get_profile(): string;
	/**
	 * Disposes the Stage3DProxy object, freeing the Context3D attached to the Stage3D.
	 */
	dispose(): void;
	/**
	 * Configures the back buffer associated with the Stage3D object.
	 * @param backBufferWidth The width of the backbuffer.
	 * @param backBufferHeight The height of the backbuffer.
	 * @param antiAlias The amount of anti-aliasing to use.
	 * @param enableDepthAndStencil Indicates whether the back buffer contains a depth and stencil buffer.
	 */
	configureBackBuffer(backBufferWidth: number, backBufferHeight: number, antiAlias: number, enableDepthAndStencil: boolean): void;
	get_enableDepthAndStencil(): boolean;
	set_enableDepthAndStencil(enableDepthAndStencil: boolean): boolean;
	get_renderTarget(): openfl_display3D_textures_TextureBase;
	get_renderSurfaceSelector(): number;
	setRenderTarget(target: openfl_display3D_textures_TextureBase, enableDepthAndStencil?: boolean, surfaceSelector?: number): void;
	clear(): void;
	present(): void;
	/**
	 * Registers an event listener object with an EventDispatcher object so that the listener receives notification of an event. Special case for enterframe and exitframe events - will switch Stage3DProxy into automatic render mode.
	 * You can register event listeners on all nodes in the display list for a specific type of event, phase, and priority.
	 *
	 * @param type The type of event.
	 * @param listener The listener function that processes the event.
	 * @param useCapture Determines whether the listener works in the capture phase or the target and bubbling phases. If useCapture is set to true, the listener processes the event only during the capture phase and not in the target or bubbling phase. If useCapture is false, the listener processes the event only during the target or bubbling phase. To listen for the event in all three phases, call addEventListener twice, once with useCapture set to true, then again with useCapture set to false.
	 * @param priority The priority level of the event listener. The priority is designated by a signed 32-bit integer. The higher the number, the higher the priority. All listeners with priority n are processed before listeners of priority n-1. If two or more listeners share the same priority, they are processed in the order in which they were added. The default priority is 0.
	 * @param useWeakReference Determines whether the reference to the listener is strong or weak. A strong reference (the default) prevents your listener from being garbage-collected. A weak reference does not.
	 */
	addEventListener(type: string, listener: (arg0: any) => void, useCapture?: boolean, priority?: number, useWeakReference?: boolean): void;
	/**
	 * Removes a listener from the EventDispatcher object. Special case for enterframe and exitframe events - will switch Stage3DProxy out of automatic render mode.
	 * If there is no matching listener registered with the EventDispatcher object, a call to this method has no effect.
	 *
	 * @param type The type of event.
	 * @param listener The listener object to remove.
	 * @param useCapture Specifies whether the listener was registered for the capture phase or the target and bubbling phases. If the listener was registered for both the capture phase and the target and bubbling phases, two calls to removeEventListener() are required to remove both, one call with useCapture() set to true, and another call with useCapture() set to false.
	 */
	removeEventListener(type: string, listener: (arg0: any) => void, useCapture?: boolean): void;
	get_scissorRect(): Engine3D_core_geom_Rectangle;
	set_scissorRect(value: Engine3D_core_geom_Rectangle): Engine3D_core_geom_Rectangle;
	/**
	 * The index of the Stage3D which is managed by this instance of Stage3DProxy.
	 */
	get_stage3DIndex(): number;
	/**
	 * The base Stage3D object associated with this proxy.
	 */
	get_stage3D(): openfl_display_Stage3D;
	/**
	 * The Context3D object associated with the given Stage3D object.
	 */
	get_context3D(): openfl_display3D_Context3D;
	/**
	 * The driver information as reported by the Context3D object (if any)
	 */
	get_driverInfo(): string;
	/**
	 * Indicates whether the Stage3D managed by this proxy is running in software mode.
	 * Remember to wait for the CONTEXT3D_CREATED event before checking this property,
	 * as only then will it be guaranteed to be accurate.
	 */
	get_usesSoftwareRendering(): boolean;
	/**
	 * The x position of the Stage3D.
	 */
	get_x(): number;
	set_x(value: number): number;
	/**
	 * The y position of the Stage3D.
	 */
	get_y(): number;
	set_y(value: number): number;
	/**
	 * The width of the Stage3D.
	 */
	get_width(): number;
	set_width(width: number): number;
	/**
	 * The height of the Stage3D.
	 */
	get_height(): number;
	set_height(height: number): number;
	/**
	 * The antiAliasing of the Stage3D.
	 */
	get_antiAlias(): number;
	set_antiAlias(antiAlias: number): number;
	/**
	 * A viewPort rectangle equivalent of the Stage3D size and position.
	 */
	get_viewPort(): Engine3D_core_geom_Rectangle;
	/**
	 * The background color of the Stage3D.
	 */
	get_color(): number;
	set_color(color: number): number;
	/**
	 * The visibility of the Stage3D.
	 */
	get_visible(): boolean;
	set_visible(value: boolean): boolean;
	/**
	 * The freshly cleared state of the backbuffer before any rendering
	 */
	get_bufferClear(): boolean;
	set_bufferClear(newBufferClear: boolean): boolean;
	get_mouse3DManager(): away3d_core_managers_Mouse3DManager;
	set_mouse3DManager(value: away3d_core_managers_Mouse3DManager): away3d_core_managers_Mouse3DManager;
	get_touch3DManager(): away3d_core_managers_Touch3DManager;
	set_touch3DManager(value: away3d_core_managers_Touch3DManager): away3d_core_managers_Touch3DManager;
	recoverFromDisposal(): boolean;
	clearDepthBuffer(): void;
	createVertexBuffer(numVertices: number, data32PerVertex: number): openfl_display3D_VertexBuffer3D;
	createIndexBuffer(numIndices: number): openfl_display3D_IndexBuffer3D;
	drawTriangles(indexBuffer: openfl_display3D_IndexBuffer3D, firstIndex?: number, numTriangles?: number): void;
	static vertexBufferCount: number;
	static indexBufferCount: number;
	static drawTriangleCount: number;
	static disposeVertexBuffer(vb: openfl_display3D_VertexBuffer3D): void;
	static disposeIndexBuffer(ib: openfl_display3D_IndexBuffer3D): void;
	static uploadVertexBufferFromVector(vb: openfl_display3D_VertexBuffer3D, data: Engine3D_core_Vector<number>, startVertex: number, numVertices: number): void;
	static uploadIndexBufferFromVector(ib: openfl_display3D_IndexBuffer3D, data: Engine3D_core_Vector<number>, startOffset: number, count: number): void;
}

