	setRenderState(stage3DProxy: away3d_core_managers_Stage3DProxy, renderable: away3d_core_base_IRenderable, vertexConstantOffset: number, vertexStreamOffset: number, camera: Engine3D_core_cameras_Camera3D): void;
	/**
	 * Verifies if the animation will be used on cpu. Needs to be true for all passes for a material to be able to use it on gpu.
	 * Needs to be called if gpu code is potentially required.
	 */
