	set_blendedRenderableHead(value: away3d_core_data_RenderableListItem): away3d_core_data_RenderableListItem;
	get_entityHead(): away3d_core_data_EntityListItem;
	/**
	 * The lights of which the affecting area intersects the camera's frustum.
	 */
