	get_directionalLights(): Engine3D_core_Vector<Engine3D_core_lights_DirectionalLight>;
	get_pointLights(): Engine3D_core_Vector<away3d_lights_PointLight>;
	get_lightProbes(): Engine3D_core_Vector<away3d_lights_LightProbe>;
